package services

import javax.inject._
import models.Order
import scala.concurrent.{ExecutionContext, Future}

@Singleton
class OrderServiceImpl @Inject()(implicit ec: ExecutionContext) extends OrderService {
  private val sampleData = Seq(
    Order(1, "Laptop", 999.99),
    Order(2, "Smartphone", 499.99)
  )

  def findById(id: Long): Future[Option[Order]] =
    Future.successful(sampleData.find(_.id == id))
}